import{_ as a,c as n,a as i,o as e}from"./app-CEcM0piI.js";const l={};function p(t,s){return e(),n("div",null,s[0]||(s[0]=[i(`<table><thead><tr><th>维度</th><th>传统架构</th><th>monorepo</th></tr></thead><tbody><tr><td>依赖管理</td><td>每个项目单独管理依赖</td><td>统一管理依赖，减少版本冲突</td></tr><tr><td>公共模块复用</td><td>需要手动同步和发布</td><td>子包间直接引用，快速构建</td></tr><tr><td>构建效率</td><td>每个项目单独构建，耗时长</td><td>按需构建，提升效率</td></tr><tr><td>磁盘占用</td><td>重复安装，磁盘占用高</td><td>去重机制，节约磁盘空间</td></tr><tr><td>协作成本</td><td>跨项目协作复杂，测试联调耗时</td><td>单仓库集中管理，便于协作</td></tr></tbody></table><ol><li>传统架构 <ul><li>独立项目结构，所有项目都是分开的github仓库</li><li>技术栈独立</li><li>规范化、自动化相关处理是项目间割裂</li><li>依赖管理，版本很难统一管理</li><li>部署，docker、docker、compose，自动化脚本很难形成统一</li></ul></li><li>monorepo架构 <ul><li>混合项目结构，所有相关的工程形成子包进行管理</li><li>技术栈高度统一，（团队基建项目、业务项目、子服务，技术栈）</li><li>规范化、自动化、流程化项目间共享</li><li>依赖管理，版本统一管理</li><li>部署，docker、docker、compose，自动化脚本统一部署流程</li></ul></li></ol><h1 id="monorepo" tabindex="-1"><a class="header-anchor" href="#monorepo"><span>monorepo</span></a></h1><p>使用pnpm的workspace来管理monorpo项目</p><ol><li>在主项目的根目录下根据不同的逻辑划分不同的工作区以便于管理 假设项目根目录为以下示例：</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>├── apps</span></span>
<span class="line"><span>│   ├── backend</span></span>
<span class="line"><span>│   └── frontend</span></span>
<span class="line"><span>├── node_modules</span></span>
<span class="line"><span>├── packages</span></span>
<span class="line"><span>│   ├── charts</span></span>
<span class="line"><span>│   ├── cli</span></span>
<span class="line"><span>│   ├── tools</span></span>
<span class="line"><span>│   └── ui</span></span>
<span class="line"><span>├── package.json</span></span>
<span class="line"><span>├── pnpm-lock.yaml</span></span>
<span class="line"><span>└── pnpm-workspace.yaml</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>apps中存放项目逻辑，其中分为前端和后端的逻辑各分一个工作区</li><li>packages中存放通用的工具等，根据职责的不同划分ui、tools、cli、charts工作区</li></ul><ol start="2"><li>在主项目的根目录中创建<code>pnpm-workspace.yaml</code>文件，并定义查找各个分包的规则</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>packages:</span></span>
<span class="line"><span>  - &#39;packages/*&#39;    //查找项目根目录下的packages文件夹中的所有工作区</span></span>
<span class="line"><span>  - &#39;apps/frontend/*&#39;    //查找项目根目录下的apps文件夹中的frontend中的所有工作区</span></span>
<span class="line"><span>  - &#39;apps/backend/*&#39;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="3"><li>不同工作区之间相互依赖 对于项目中不同工作区的依赖引用，monorepo使用的是链接机制：当前工作区若依赖了本地其他工作区的内容，需要在package.json中配置引用和引用路径，如：</li></ol><div class="language-package.json line-numbers-mode" data-highlighter="shiki" data-ext="package.json" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>  &quot;dependencies&quot;: {</span></span>
<span class="line"><span>    &quot;react&quot;: &quot;^19.0.0&quot;,</span></span>
<span class="line"><span>    &quot;react-dom&quot;: &quot;^19.0.0&quot;,</span></span>
<span class="line"><span>    &quot;@miaoma/ui&quot;: &quot;workspace:*&quot;,</span><span>    //本地工作区依赖</span></span>
<span class="line"><span>    &quot;@miaoma/cli&quot;: &quot;workspace:*&quot;</span><span>    //本地工作区依赖</span></span>
<span class="line"><span>  },</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>workspace:*</code>表示在主项目的所有目录中搜索该包，也可以手动指定路径 之后使用<code>pnpm i</code>命令安装依赖时会在node_models文件夹中创建该报名的文件夹并将链接指向找到的包位置，不会多余的安装</p><h1 id="微前端" tabindex="-1"><a class="header-anchor" href="#微前端"><span>微前端</span></a></h1><p>微前端是借鉴了微服务的理念，将一个庞大的应用拆分成多个独立灵活的小型应用，每个应用都可以独立开发，独立运行，独立部署，还可以随意组合，这样就降低了耦合度，从而更加灵活。</p><p><strong>iframe</strong> 通过iframe实现就是每个子应用通过iframe标签来嵌入到父应用中，iframe具有天然的隔离属性，各个子应用之间以及子应用和父应用之间都可以做到互不影响。</p><p>但是iframe也有很多缺点：</p><ol><li>url不同步，如果刷新页面，iframe中的页面的路由会丢失。</li><li>全局上下文完全隔离，内存变量不共享。</li><li>Ui不同步，比如iframe中的页面如果有带遮罩层的弹窗组件，则遮罩就不能覆盖整个浏览器，只能在iframe中生效。</li><li>慢。每次子应用进入都是一次浏览器上下文重建、资源重新加载的过程。</li></ol><p><strong>single-spa</strong> single-spa是最早的微前端框架，可以兼容很多技术栈。 single-Spa首先在基座中注册所有子应用的路由，当URL改变时就会去进行匹配，匹配到哪个子应用就会去加载对应的那个子应用。 相对于iframe的实现方案，single-spa中基座和各个子应用之间共享着一个全局上下文，并且不存在URL不同步和UI不同步的情况，但是single-spa也有以下的缺点：</p><ol><li>没有实现js隔离和css隔离</li><li>需要修改大量的配置，包括基座和子应用的，不能开箱即用</li></ol><p><strong>qiankun</strong> qiankun是阿里开源的一个微前端的框架，在阿里内部已经经过一批线上应用的充分检验及打磨了，所以可以放心使用。</p><p>qiankun优势：</p><ol><li>基于single-spa封装的，提供了更加开箱即用的API</li><li>技术栈无关，任意技术栈的应用均可使用/接入，不论是React/Vue/Angular/JQuery还是其他等框架。</li><li>HTML Entry的方式接入，像使用iframe一样简单</li><li>实现了single-spa不具备的样式隔离和js隔离</li><li>资源预加载，在浏览器空闲时间预加载未打开的微应用资源，加速微应用打开速度。</li></ol><h2 id="qiankun" tabindex="-1"><a class="header-anchor" href="#qiankun"><span>qiankun</span></a></h2><ul><li>基座（主应用）：主要负责集成所有的子应用，提供一个入口能够访问你所需要的子应用的展示，尽量不写复杂的业务逻辑</li><li>子应用：根据不同业务划分的模块，每个子应用都打包成umi模块的形式供基座（主应用）来加载</li></ul><p>底层原理js沙箱使用的是proxy进行快照然后用用with（window)0包惠起来with内的window其实就是proxy.window我们声明变量varname=&#39;小满&#39;实际这个变量挂到了proxy.window并不是真正的window css沙箱原理第一个就是shadowDom隔离第二个类似于Vue的scoped</p><h1 id="硬链接和软链接" tabindex="-1"><a class="header-anchor" href="#硬链接和软链接"><span>硬链接和软链接</span></a></h1><h2 id="索引节点方式-硬链接" tabindex="-1"><a class="header-anchor" href="#索引节点方式-硬链接"><span>索引节点方式（硬链接）</span></a></h2><p>多个链接的索引节点指针指向的是同一个文件，同时索引节点中设置一个链接计数count，用来表示链接到本索引节点上的用户目录项的数目 任何用户对共享文件进行的修改都会引起其相应结点内容的改变（如文件长度改变），其他用户也能看到改变，从而方便共享 当用户不再使用该文件的时候，就断开链接，count的值也随之改变（-1)</p><h2 id="符号链接方式-软链接" tabindex="-1"><a class="header-anchor" href="#符号链接方式-软链接"><span>符号链接方式（软链接）</span></a></h2><p>这种方式只有文件主才有指向索引结点的指针 共享文件的其他用户只有路径名，没有指向索引节点的指针 文件拥有者删除共享文件后，其他用户如果试图通过符号链访问该文件 系统会找不到该文件访问失败，然后删除符号链</p><p>软链接的链接计数恒为1</p>`,31)]))}const r=a(l,[["render",p]]),o=JSON.parse('{"path":"/front/engineering/4/","title":"4 pnpm","lang":"zh-CN","frontmatter":{"title":"4 pnpm","createTime":"2025/06/18 21:13:00","permalink":"/front/engineering/4/"},"readingTime":{"minutes":5.73,"words":1718},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/工程化/4 pnpm.md","headers":[]}');export{r as comp,o as data};
